def strategy(candles, i, indicators, open_trades):
    closes = [c.close for c in candles[:i+1]]
    if len(closes) < 50:
        return []
    actions = []
    _smc_ob_b = indicators.get('smc_ob_bull', {})
    _smc_ob_b_val = _lookup_nearest(_smc_ob_b, candles[i].time)
    _smc_ob_r = indicators.get('smc_ob_bear', {})
    _smc_ob_r_val = _lookup_nearest(_smc_ob_r, candles[i].time)
    if not open_trades:
        if not (_smc_ob_b_val is None) and _smc_ob_b_val is not None and _smc_ob_b_val == True:
            actions.append({"action": "buy"})
        elif not (_smc_ob_r_val is None) and _smc_ob_r_val is not None and _smc_ob_r_val == True:
            actions.append({"action": "sell"})
    if open_trades:
        rsi_ex = rsi(closes, 14)
        if rsi_ex[i] is not None and rsi_ex[i] > 75:
            actions.append({"action": "close"})
    return actions
